// Vikunja outgoing webhook payload (event=task.updated|task.created):
// { event_name, time, data: { task: { id, title, description, labels, done, ... } } }
//
// Trigger condition: task has a label called `agent` (case-insensitive) AND
// is not already done. The `agent` label is consumed (we set done:false +
// post a comment) — but we leave the label on the task so you can re-trigger
// by toggling done back to false.
const body = $input.first().json.body || $input.first().json;
const event = body.event_name || body.event || '';
const task = (body.data && body.data.task) || body.task;
if (!task) { throw new Error('No `task` in webhook payload'); }
if (event !== 'task.created' && event !== 'task.updated') {
  return [{ json: { skipped: true, reason: `event=${event}` } }];
}
if (task.done) {
  return [{ json: { skipped: true, reason: 'task already done' } }];
}

const labels = (task.labels || []).map(l => (l.title || l.name || '').toLowerCase());
const TRIGGER = ($env.AGENT_TRIGGER_LABEL || 'agent').toLowerCase();
if (!labels.includes(TRIGGER)) {
  return [{ json: { skipped: true, reason: `no '${TRIGGER}' label` } }];
}

const systemPrompt = $env.AGENT_SYSTEM_PROMPT ||
  'You are a senior software engineer assistant. The user will give you a coding task. ' +
  'Respond with: 1) a short plan, 2) the concrete code changes (use diffs or full file contents with paths), ' +
  '3) any commands the user should run. Be precise and minimal.';

return [{
  json: {
    task_id: task.id,
    task_title: task.title,
    chat: {
      model: $env.AGENT_MODEL || 'openclaw',
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user',   content: `# ${task.title}\n\n${task.description || '(no description)'}` },
      ],
      temperature: 0.2,
      stream: false,
    },
  },
}];

// Pull the assistant message out of an OpenAI chat completion response.
const body = $input.first().json;
const content = body && body.choices && body.choices[0] && body.choices[0].message && body.choices[0].message.content;
if (!content) { throw new Error('Agent returned no content. Body=' + JSON.stringify(body).slice(0, 500)); }
const meta = $('Build agent request').first().json;
return [{ json: { task_id: meta.task_id, comment: `🤖 **Agent response** (model: ${meta.chat.model}):\n\n${content}` } }];
